  1	/* eslint-disable @typescript-eslint/no-explicit-any */
  2	import { ResourceYAMLEditor } from '@openshift-console/dynamic-plugin-sdk';
  3	import { FormHelperText, PageSection, Title } from '@patternfly/react-core';
  4	import { UiSchema } from '@rjsf/utils';
  5	import _ from 'lodash';
  6	import React, { FC, Suspense } from 'react';
  7	import { useTranslation } from 'react-i18next';
  8	import { safeYAMLToJS } from '../../utils/yaml';
  9	import { SchemaValidator } from './config/validator';
 10	import { DynamicForm } from './dynamic-form/dynamic-form';
 11	import { ErrorTemplate } from './dynamic-form/templates';
 12	import { EditorToggle, EditorType } from './editor-toggle';
 13	import './forms.css';
 14	import { ResourceDeleteModal } from './resource-delete-modal';
 15	import { Consumer } from './resource-watcher';
 16	
 17	export type ResourceFormProps = {
 18	  uiSchema: UiSchema;
 19	};
 20	
 21	export const ResourceForm: FC<ResourceFormProps> = ({ uiSchema }) => {
 22	  const { t } = useTranslation('plugin__netobserv-plugin');
 23	  const [viewType, setViewType] = React.useState(EditorType.CUSTOM);
 24	  const [data, setData] = React.useState<any>(null);
 25	  const [isDeleteModalOpen, setDeleteModalOpen] = React.useState(false);
 26	
 27	  const hasChanged = React.useCallback(
 28	    (existing: any) => {
 29	      return data?.metadata?.resourceVersion !== existing?.metadata?.resourceVersion;
 30	    },
 31	    [data?.metadata?.resourceVersion]
 32	  );
 33	
 34	  return (
 35	    <Consumer>
 36	      {ctx => {
 37	        // first init data when watch resource query got results
 38	        if (data == null) {
 39	          setData(ctx.data);
 40	        }
 41	        return (
 42	          <PageSection id="pageSection">
 43	            <div id="pageHeader">
 44	              <Title headingLevel="h1" size="2xl">
 45	                {ctx.isUpdate ? t('Update {{kind}}', { kind: ctx.kind }) : t('Create {{kind}}', { kind: ctx.kind })}
 46	              </Title>
 47	              <FormHelperText style={{ marginTop: 'var(--pf-t--global--spacer--xs)' }}>
 48	                {ctx.isUpdate
 49	                  ? t('Update by completing the form. Current values are from the existing resource.')
 50	                  : t('Create by completing the form. Default values are provided as example.')}
 51	              </FormHelperText>
 52	            </div>
 53	            <Suspense fallback={<></>}>
 54	              <EditorToggle
 55	                type={viewType}
 56	                updated={hasChanged(ctx.data)}
 57	                isUpdate={ctx.isUpdate}
 58	                onReload={() => setData(ctx.data)}
 59	                onChange={setViewType}
 60	                onSubmit={() => ctx.onSubmit(data)}
 61	                onCancel={() => window.history.back()}
 62	                onDelete={() => setDeleteModalOpen(true)}
 63	                customChild={
 64	                  ctx.schema ? (
 65	                    <DynamicForm
 66	                      showAlert
 67	                      formData={data}
 68	                      schema={ctx.schema}
 69	                      uiSchema={uiSchema} // see if we can regenerate this from CSV
 70	                      validator={SchemaValidator}
 71	                      errors={ctx.errors}
 72	                      onError={errs => ctx.setErrors(_.map(errs, error => error.stack))}
 73	                      onChange={event => setData(event.formData)}
 74	                      skipDefaults={ctx.skipDefaults}
 75	                    />
 76	                  ) : (
 77	                    <></>
 78	                  )
 79	                }
 80	                yamlChild={
 81	                  <>
 82	                    <ResourceYAMLEditor
 83	                      initialResource={data}
 84	                      onSave={content => {
 85	                        const updatedData = safeYAMLToJS(content);
 86	                        setData(updatedData);
 87	                        ctx.onSubmit(updatedData);
 88	                      }}
 89	                    />
 90	                    <>{ctx.errors.length > 0 && <ErrorTemplate errors={ctx.errors} />}</>
 91	                  </>
 92	                }
 93	              />
 94	            </Suspense>
 95	            {isDeleteModalOpen && (
 96	              <ResourceDeleteModal
 97	                data={ctx.data}
 98	                kind={ctx.kind}
 99	                onDelete={() => ctx.onSubmit(data, true)}
100	                onCancel={() => setDeleteModalOpen(false)}
101	              />
102	            )}
103	          </PageSection>
104	        );
105	      }}
106	    </Consumer>
107	  );
108	};
109	
110	export default ResourceForm;

